import{_ as a,C as c,o as s,c as l,j as o,a as i,E as r,a2 as t}from"./chunks/framework.C90q7Ucc.js";const I=JSON.parse('{"title":"CodeLark 当前架构","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/current.md","filePath":"architecture/current.md","lastUpdated":1781274272000}'),n={name:"architecture/current.md"};function p(u,e,h,m,g,b){const d=c("MermaidDiagram");return s(),l("div",null,[e[0]||(e[0]=o("h1",{id:"codelark-当前架构",tabindex:"-1"},[i("CodeLark 当前架构 "),o("a",{class:"header-anchor",href:"#codelark-当前架构","aria-label":'Permalink to "CodeLark 当前架构"'},"​")],-1)),e[1]||(e[1]=o("h2",{id:"一眼看整体",tabindex:"-1"},[i("一眼看整体 "),o("a",{class:"header-anchor",href:"#一眼看整体","aria-label":'Permalink to "一眼看整体"'},"​")],-1)),e[2]||(e[2]=o("p",null,[i("CodeLark 的核心不是“把 IM 消息转发给一个模型 API”，而是把 IM、Web 工作台、本地 Codex / Claude Code 会话和飞书卡片都收敛到同一个 "),o("code",null,"BridgeSession"),i(" 生命周期里。IM 只是入口，"),o("code",null,"BridgeSession"),i(" 是 CodeLark 自己维护的会话边界，Codex thread / Claude session 才是底层 runtime 的真实会话。")],-1)),r(d,{code64:""}),e[3]||(e[3]=t('<p>设计上有三条主线：</p><ul><li>会话边界先于平台边界：聊天、Web 页面和本地 runtime 都先落到 <code>BridgeSession</code>，再决定路由到哪个 provider。</li><li>并发边界先于代码入口：所有入口都先进入 lane，确保控制命令、长任务、普通 prompt 和会话变更不会互相重排。</li><li>展示边界先于平台实现：SDK stream 和 JSONL mirror 都进入统一 turn progress，再由 Feishu adapter 决定如何做卡片增量更新。</li></ul><p>重要模块按职责分组。这里只先讲责任，不列源码入口；具体入口放到各模块小节里。</p><table tabindex="0"><thead><tr><th>模块</th><th>设计职责</th></tr></thead><tbody><tr><td>通道 adapter</td><td>把平台事件转换成统一消息，把输出转换成平台文本、卡片或附件。</td></tr><tr><td>Bridge host</td><td>维护 daemon 生命周期，并把通道、命令、turn、mirror、权限和健康检查装配在一起。</td></tr><tr><td>BridgeSession</td><td>表达“当前聊天对应哪条本地工作会话”，承载 runtime 身份、工作目录和会话级设置。</td></tr><tr><td>Lane 调度</td><td>表达“这条消息要和谁互相等待”，决定控制命令、长任务、普通命令和 prompt 的并发关系。</td></tr><tr><td>Runtime provider</td><td>屏蔽 Codex SDK、Codex pty、Codex tmux、Claude tmux、Claude pty、Claude SDK 的底层差异。</td></tr><tr><td>Mirror 与 Stream UI</td><td>把本地 JSONL 变化聚合为 turn progress，并用卡片 diff 推送到 IM。</td></tr></tbody></table><h2 id="消息投递到后端" tabindex="-1">消息投递到后端 <a class="header-anchor" href="#消息投递到后端" aria-label="Permalink to &quot;消息投递到后端&quot;">​</a></h2><p>普通 IM 文本进入后端前，先被归一成平台无关的内部消息。后端接着要解决的核心问题不是“调用哪个函数”，而是“这条消息要不要等别人”。有些消息必须保持顺序，比如同一个工作会话里的两个 prompt；有些消息应该马上处理，比如 <code>/stop</code>；有些消息可以和 prompt 同时跑，比如看状态、看 screen、跑 shell。lane 就是 CodeLark 用来表达这组等待关系的名字。</p>',6)),r(d,{code64:""}),e[4]||(e[4]=t('<h3 id="先区分三个问题" tabindex="-1">先区分三个问题 <a class="header-anchor" href="#先区分三个问题" aria-label="Permalink to &quot;先区分三个问题&quot;">​</a></h3><p><code>BridgeSession</code> 回答“这条聊天现在连着哪条工作会话”。它保存底层 Codex thread、Claude session、tmux provider 会话名、运行健康和消息生命周期等身份/状态；当前工作目录、模型、provider、sandbox、reasoning 等用户配置覆盖已经迁到 Session TOML。一个 IM 群聊、Web 工作台入口或本地接管动作，最后都要落到某个 <code>BridgeSession</code>，再按 scoped TOML 解析 effective runtime 配置。</p><p>Lane 回答“这条消息要和谁互相等待”。同一条 lane 里的消息按顺序执行；不同 lane 里的消息，默认认为互不影响，可以同时执行。它解决的是并发边界：哪些事情必须排队，哪些事情不应该互相拖慢。</p><p><code>SessionExecutor</code> 回答“同一条工作会话里怎么保证一次只跑一个 prompt 或配置变更”。普通 prompt 和 <code>/provider</code>、<code>/model</code> 这类会改变会话状态的命令进入 <code>session:&lt;session_id&gt;</code> 后，还要经过这个会话锁。不同 session 可以并行；同一 session 保持顺序，并维护 queued/running/idle 状态。</p><h3 id="lane-是什么" tabindex="-1">Lane 是什么 <a class="header-anchor" href="#lane-是什么" aria-label="Permalink to &quot;Lane 是什么&quot;">​</a></h3><p>Lane 可以理解成“等待关系的名字”。调度层会给每条消息一个 lane 名字：名字相同，说明它们碰的是同一块状态，要按顺序来；名字不同，说明它们大概率互不影响，可以并行。</p><p>这套模型的重点是“并发可以发生，但只发生在不会破坏语义的地方”。例如两个不同工作会话的 prompt 可以一起跑；同一个工作会话的两个 prompt 必须一个接一个跑；<code>/stop</code> 不应该排在长任务后面；<code>/provider claude</code> 后面的 prompt 必须等 provider 切换完成。</p><p>当前主要有四类 lane：</p><ul><li><code>control:*</code>：控制通道。<code>/stop</code>、权限快捷回复、screen stop callback 走这里。它们的价值是“马上生效”，所以不等普通对话和长任务。</li><li><code>job:*</code>：长 I/O 通道。<code>/shell</code>、<code>/tmux-screen</code>、<code>/pty-screen</code> 走这里。它们可能跑很久，所以不占住同一 session 的 prompt 队伍；其中 <code>/tmux-screen</code>、<code>/pty-screen</code> 是监控命令，不等待普通 conversation barrier，避免排在卡住的普通对话后面；<code>/shell</code> 等普通 job 仍会先等同一聊天前面的会话配置变更或普通 prompt barrier 完成。</li><li><code>chat:&lt;channel&gt;:&lt;chat&gt;</code>：聊天通道。只读命令、普通 callback、状态查询这类不改 session 状态的交互走这里。<code>channel</code> 和 <code>chat</code> 的作用是把不同平台、不同群聊或私聊隔开：A 群的状态查询不会挡住 B 群，飞书群聊也不会和别的通道混在一起。</li><li><code>session:&lt;session_id&gt;</code>：工作会话通道。普通 prompt、会话配置变更、会切换绑定的 callback 走这里。它按 <code>BridgeSession.id</code> 区分，而不是按群聊区分，因为多个入口可能绑定同一条本地工作会话；只要它们操作的是同一个 session，就必须保持同一份上下文和配置的顺序。</li></ul><p><code>chat</code> 和 <code>session</code> 分开，是因为它们保护的东西不同。<code>chat</code> 保护的是“这一个聊天里的轻量交互不要互相打架”；<code>session</code> 保护的是“这条工作会话的上下文、provider、模型、cwd 和底层 runtime 身份不要乱序”。一个聊天可以重新绑定到别的 session；多个聊天也可能观察或接管同一个 session。用两个维度拆开，才能让只读交互快起来，同时保住真正需要一致性的工作会话。</p><h3 id="barrier-是什么" tabindex="-1">Barrier 是什么 <a class="header-anchor" href="#barrier-是什么" aria-label="Permalink to &quot;Barrier 是什么&quot;">​</a></h3><p>conversation barrier 是 lane 之上的保护规则，用来处理“这条命令会改变后面消息应该怎么解释”的场景。模型、provider、工作目录、runtime 设置、thread 绑定等变化完成前，同一聊天里后续非 control 的 command/job/prompt 都要等待。</p><p>直观例子：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/provider claude</span></span>\n<span class="line"><span>请继续刚才的任务</span></span></code></pre></div><p>如果没有 barrier，第二条普通 prompt 可能先进入旧 provider。barrier 的作用就是让这类“先改配置，再发任务”的用户意图保持顺序。它按聊天生效，而不是全局生效，所以不会让别的群聊一起停住。</p><h3 id="处理步骤" tabindex="-1">处理步骤 <a class="header-anchor" href="#处理步骤" aria-label="Permalink to &quot;处理步骤&quot;">​</a></h3><p>普通 IM 文本消息进入当前 runtime 的主路径：</p><ol><li>平台 adapter 接收飞书事件，转换成内部消息。</li><li>adapter loop 从队列取消息，先识别它是平台事件、callback、命令、权限快捷回复、控制输入，还是普通 prompt。</li><li>调度层为消息选择 lane。控制消息直接走 control lane；长 I/O 走 job lane；只读命令走 chat lane；prompt 和会话变更进入 session lane。</li><li>如果消息会改变会话配置或绑定，它会声明 conversation barrier，阻止同一聊天后续非 control 消息抢跑。</li><li>session lane 进入同一 session 的串行队伍，更新 queued/running/idle 状态，并在相邻 turn 之间保留短 cooldown。</li><li>普通 prompt 解析当前聊天绑定的 <code>BridgeSession</code>，建立本次 turn 的任务状态、abort controller、stream UI 和最终 delivery。</li><li>provider 路由根据 session 上的 runtime/provider 设置选择 Codex 或 Claude 的具体执行方式。</li><li>provider 创建或继续底层 runtime 会话，并把必要身份写回 session。</li><li>delivery pipeline 把最终文本、卡片、附件等发回对应 IM channel。</li></ol><h3 id="模块入口" tabindex="-1">模块入口 <a class="header-anchor" href="#模块入口" aria-label="Permalink to &quot;模块入口&quot;">​</a></h3><ul><li>adapter 队列和 lane 调度：<code>src/channels/adapter-runtime/runtime.ts</code></li><li>bridge host 装配与消息处理：<code>src/bridge/host/manager.ts</code></li><li>会话串行执行：<code>src/bridge/session/session-executor.ts</code></li><li>普通 prompt turn：<code>src/bridge/turn/interactive/runner.ts</code></li><li>provider 路由：<code>src/runtime/codex/routing-provider.ts</code></li></ul><h2 id="t-接管本地-codex-线程" tabindex="-1"><code>/t</code> 接管本地 Codex 线程 <a class="header-anchor" href="#t-接管本地-codex-线程" aria-label="Permalink to &quot;`/t` 接管本地 Codex 线程&quot;">​</a></h2><p><code>/t</code> 命令用于把本机可发现的 Codex thread 接入 IM。</p><p>典型过程：</p><ol><li>用户发送 <code>/t</code>。</li><li>local Codex session index 扫描 <code>~/.codex/sessions/**/*.jsonl</code>。</li><li>bridge 返回最近的本地 Codex 线程列表。</li><li>用户发送 <code>/t 1</code>。</li><li>被选中的 Codex thread 会被 materialize 成一个 <code>BridgeSession</code>，或复用已有同 thread 的 <code>BridgeSession</code>。</li><li>当前 IM chat 创建或更新 <code>ChannelChat</code>，让它指向这个 <code>BridgeSession.id</code>。</li><li>后续普通消息通过 ChannelChat 找到 session，再通过 <code>BridgeSession.codex_thread_id</code> 继续同一条 Codex thread。</li></ol><p>因此 <code>/t</code> 不是“把 thread id 写到聊天上”，而是“把 Codex thread 纳入 BridgeSession，再让聊天绑定这个 BridgeSession”。</p><h2 id="mirror-运行时" tabindex="-1">Mirror 运行时 <a class="header-anchor" href="#mirror-运行时" aria-label="Permalink to &quot;Mirror 运行时&quot;">​</a></h2><p>Mirror 是对本地 runtime JSONL 文件的持续观察。它让 IM 能看到本地 Codex TUI、Codex Native 或 Claude Code 在同一条会话里继续产生的输出。</p>',27)),r(d,{code64:""}),e[5]||(e[5]=t('<h3 id="设计理念" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念" aria-label="Permalink to &quot;设计理念&quot;">​</a></h3><p>Mirror 不是子线程，也不是独立 worker。它运行在 bridge daemon 内：<code>fs.watch</code> 只负责标记 dirty 和唤醒 debounce；poll timer 负责兜底；真正处理发生在 reconcile 批次里。批次对不同 subscription 使用有界并发，同一个 subscription 内部按 JSONL cursor 顺序读取、过滤、reduce、触发 hook，避免一张 mirror 卡片的局部更新乱序。</p><p>Mirror 的身份分两层，不应混用。第一层是“哪个本地会话文件”，由 <code>BridgeSession</code>、runtime identity 和 cwd 决定；第二层是“文件内哪一轮 turn”，由 runtime-specific parser 从 JSONL 记录关系里推断。文件名只回答“观察哪个会话”，不能回答“这是第几轮输出”。</p><p>Mirror 和主动 IM turn 之间有显式归属规则。当前 IM 发起的 prompt 会产生本地 JSONL 回声，suppression 会过滤重复回显；如果新增记录包含可被 active turn 接受的 <code>task_complete</code> / <code>task_aborted</code>，<code>routeRuntimeRecords</code> 会通过 <code>TurnCoordinator.claimRuntimeTerminal</code> 把终态归还给 active turn。未被 claim 的记录才作为独立 mirror delivery。</p><h3 id="重要模块" tabindex="-1">重要模块 <a class="header-anchor" href="#重要模块" aria-label="Permalink to &quot;重要模块&quot;">​</a></h3><p>Mirror 主路径：</p><ol><li>订阅规划找到有本地 runtime 身份的 <code>BridgeSession</code>，再找到绑定这些 session 的 <code>ChannelChat</code>。</li><li>订阅 runtime 根据绑定关系建立或更新 subscription。</li><li>每个 subscription 通过当前 runtime source 定位对应 JSONL 文件。</li><li>文件监听和定时 reconcile 读取新增记录；订阅间有界并发，单订阅内部按 cursor 顺序处理。</li><li>suppression 去掉当前 IM 发起 turn 造成的重复回显。</li><li>turn reducer 把 JSONL 事件合并成可展示 turn。</li><li>feedback controller 更新流式卡片或发送最终 fallback 消息。</li></ol><p>Codex mirror 的身份链路是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>codex_thread_id -&gt; BridgeSession -&gt; ChannelChat -&gt; channel/chat</span></span></code></pre></div><p>Claude Code mirror 的身份链路是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>runtime.claude.sessionId + runtime.claude.cwd -&gt; BridgeSession -&gt; ChannelChat -&gt; channel/chat</span></span></code></pre></div><p>如果 JSONL source 连续多次无法定位，mirror 订阅层会通过 runtime-neutral identity cleanup hook 清理当前 runtime 身份：Codex 清理 <code>runtime.codex.threadId</code>，Claude Code 清理 <code>runtime.claude.sessionId</code> / <code>runtime.claude.cwd</code>。这样 dangling 本地线程不会在 subscription registry 里反复重建。</p><p>Mirror subscription registry 采用兴趣驱动分层策略。bridge 会为最近触达的 <code>ChannelChat</code> 保持热订阅并低延迟 reconcile；长期未触达的绑定仍保留 mirror 订阅，但按低频冷检查节奏调度，避免冷群抢占热群预算。用户消息或卡片回调会刷新 <code>lastActivityAt</code>，让该聊天重新进入热同步窗口。</p><p><code>routeCodexRecords</code> 和 <code>claimCodexTerminal</code> 仍作为兼容入口保留；新代码应优先 使用 runtime-neutral 的 <code>routeRuntimeRecords</code> 和 <code>claimRuntimeTerminal</code>。</p><p>源码入口：</p><ul><li>订阅规划：<code>src/bridge/mirror/subscription-registry.ts</code></li><li>订阅、watch、poll 和 reconcile：<code>src/bridge/mirror/runtime.ts</code></li><li>reconcile 细节与有界并发：<code>src/bridge/mirror/reconcile-core.ts</code>、<code>src/bridge/mirror/reconcile-batch.ts</code></li><li>回声抑制：<code>src/bridge/mirror/suppression.ts</code></li><li>active turn 终态归属：<code>src/bridge/turn/turn-coordinator.ts</code></li></ul><h3 id="mirror-消息渲染链路" tabindex="-1">Mirror 消息渲染链路 <a class="header-anchor" href="#mirror-消息渲染链路" aria-label="Permalink to &quot;Mirror 消息渲染链路&quot;">​</a></h3><p>当前 mirror 卡片渲染链路以 <code>BridgeMirrorRecord</code> 为输入，以 Feishu CardKit 局部更新为输出。先看完整链路：</p>',18)),r(d,{code64:""}),e[6]||(e[6]=t(`<h4 id="设计理念-1" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念-1" aria-label="Permalink to &quot;设计理念&quot;">​</a></h4><p>Mirror 渲染不把每条 record 直接投递到飞书。record 先被 reducer 合并为一轮可展示进展，再通过 hook 推给 stream UI，最后由 Feishu adapter 把“期望状态”和“已渲染状态”做 diff。这样可以把高频 JSONL 写入折叠成低频卡片更新，并且只更新发生变化的 element。</p><p><code>cardElement.content</code> 是固定正文、任务、状态区的正常快路径，不是唯一更新手段。工具和 history 结构变化需要 create/patch；多条结构更新可合并为 <code>card.batchUpdate</code>；metadata、actions、layout signature、shadow trust 或失败恢复不安全时走 full refresh。</p><h4 id="重要模块-1" tabindex="-1">重要模块 <a class="header-anchor" href="#重要模块-1" aria-label="Permalink to &quot;重要模块&quot;">​</a></h4><p>Turn reducer 会按 record 类型更新同一个 <code>BridgeMirrorTurnState</code>：</p><ul><li><code>message:user</code>：写入 <code>userText</code>，同时写入 unified history user item。</li><li><code>message:assistant</code> 和 <code>message:commentary</code>：去掉近距离重复文本后追加到 <code>streamedText</code>，记录 <code>lastContentResponseAt</code>，并写入 unified history model item。</li><li><code>message:system</code>：写入 unified history system item。</li><li><code>reasoning</code>：写入 <code>statusNote</code>。</li><li><code>plan_update</code>：写入 <code>taskItems</code>。</li><li><code>tool_started</code> / <code>tool_finished</code>：转换成 Codex turn event 后写入 <code>toolCalls</code>。</li><li><code>context_usage</code>：写入 <code>contextUsage</code>。</li><li><code>goal_status</code>：写入 <code>goalStatus</code>；如果当前 turn 已经有正文、用户文本、工具或任务进展，才触发正文区域刷新。只有 active goal 状态、没有可见进展的空 turn 不会启动 mirror stream。</li><li><code>task_complete</code> / <code>task_aborted</code>：结束当前 pending turn，形成 <code>FinalizedBridgeMirrorTurn</code>；如果 active turn 能 claim 这个终态，则交给 active IM turn，否则作为 mirror final delivery。连续 3 个只有 active goal 状态、没有可见进展的空 turn 会产生一次 goal loop warning，避免无限重启时刷出空镜像卡片。</li></ul><p>Feedback controller 把 reducer hook 映射到 stream UI：</p><ul><li><code>onStreamText</code> 调 <code>formatMirrorMessage(baseTitle, userText, streamedText, ...)</code> 生成主内容字符串，并推给 <code>pushStreamFeedbackText()</code>；同时推 history 和 status。</li><li><code>onTaskProgress</code> 推 <code>pushStreamFeedbackTasks()</code>。</li><li><code>onToolProgress</code> 推 <code>pushStreamFeedbackTools()</code> 和 history。</li><li><code>onStatusProgress</code> 只刷新状态区；长时间无正文时，<code>refreshMirrorStreamingStatus()</code> 会按 idle/heartbeat 配置补心跳状态。</li></ul><p>这些 push 最终进入 Feishu adapter 的流式接口。adapter 不立即对每个事件发远端请求，而是更新本地 desired state：</p><ul><li><code>onStreamText</code> -&gt; <code>pendingText</code></li><li><code>onStreamStatus</code> -&gt; <code>pendingStatusText</code></li><li><code>onTaskEvent</code> / <code>onStreamTasks</code> -&gt; <code>pendingTasksText</code></li><li><code>onToolEvent</code> / <code>onStreamTools</code> -&gt; <code>toolCalls</code></li><li><code>onStreamHistory</code> -&gt; <code>historyItems</code></li><li><code>onStreamMetadata</code> -&gt; <code>metadata</code></li><li><code>onStreamActions</code> -&gt; <code>actionRows</code></li></ul><p>每次 desired state 变化都会标记 <code>desiredRevision</code> 并调用 <code>scheduleCardFlush()</code>。<code>flushCardUpdate()</code> 只在 flush tick 读取一份 desired snapshot，构造 desired render，再和本地 remote shadow 比较：</p><ul><li>正文、任务、状态内容变化且布局没变时，生成 <code>content</code> 更新，通常只对 <code>streaming_content</code>、<code>streaming_tasks</code>、<code>streaming_status</code> 调 <code>cardElement.content</code>。</li><li>history/tool 追加或 patch 时，生成 <code>create</code> / <code>patch</code> 更新；多条 create/patch 可合并为 <code>card.batchUpdate</code>。</li><li>为降低 CardKit <code>batchUpdate</code> 被服务端接受但客户端不重绘的风险，planner 会把两类增量直接改判为 full refresh：history 中出现用户文本更新；desired card 组件数不超过 20 且本轮 create/patch 原本会形成实际 <code>card.batchUpdate</code>。</li><li>metadata、actions、layout signature、shadow trust 或 history/tool 结构不再可证明安全时，走 full refresh，即 <code>card.update:streaming_refresh</code>。</li><li>组件数接近上限时，先 rollover 到 continuation card，失败后再 full refresh。</li></ul><p>因此“只对变化 element 调 <code>cardElement.content</code>”是正文、任务、状态这类固定元素的正常快路径；当前实现还保留 create/patch、batchUpdate、direct full refresh 和 rollover 作为工具/history/结构变化与失败恢复路径。sync plan 日志会记录 desired component count、direct refresh 阈值、增量 action 类型/element IDs、是否命中用户文本更新和 direct refresh rule，便于核对 planner 分流。</p><p>源码入口：</p><ul><li>turn reducer：<code>src/bridge/mirror/turns.ts</code></li><li>mirror 正文格式化：<code>src/bridge/mirror/formatters.ts</code></li><li>feedback hooks：<code>src/bridge/mirror/feedback-controller.ts</code></li><li>stream UI 抽象：<code>src/channels/delivery/stream-feedback.ts</code></li><li>Feishu desired/shadow diff：<code>src/channels/feishu/adapter.ts</code></li></ul><h3 id="mirror-文件索引与-turn-索引" tabindex="-1">Mirror 文件索引与 turn 索引 <a class="header-anchor" href="#mirror-文件索引与-turn-索引" aria-label="Permalink to &quot;Mirror 文件索引与 turn 索引&quot;">​</a></h3><p>第一层是文件索引，用来定位要读哪个本地会话文件：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>BridgeSession + runtime identity + cwd</span></span>
<span class="line"><span>  -&gt; runtime JSONL file</span></span></code></pre></div><p>Codex 主要使用 <code>codex_thread_id</code> 定位 Codex JSONL。Claude Code 使用 <code>runtime.claude.sessionId + cwd</code> 定位：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.claude/projects/&lt;encoded-cwd&gt;/&lt;claude-session-id&gt;.jsonl</span></span></code></pre></div><p>这一层不使用 <code>uuid</code> 或 <code>parentUuid</code>。文件名和 cwd 只回答“这个 BridgeSession 应该观察哪个 Claude 会话文件”。</p><p>第二层是文件内 turn 索引，用来判断同一个 JSONL 文件里哪些行属于同一次用户请求。 一个 Claude Code prompt 通常不是单行，而是一条链：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user prompt                  uuid=A</span></span>
<span class="line"><span>skill listing attachment     uuid=B parentUuid=A</span></span>
<span class="line"><span>assistant text               uuid=C parentUuid=B</span></span>
<span class="line"><span>assistant tool_use           uuid=D parentUuid=C</span></span>
<span class="line"><span>tool_result                  uuid=E parentUuid=D</span></span>
<span class="line"><span>interrupt / continuation     uuid=F parentUuid=E</span></span></code></pre></div><p>这些行都属于同一轮 turn，mirror 应合成同一张卡。文件名只能说明“同一个会话”， 不能说明“这是第几轮”，因此仍需要文件内 turn identity。</p><p>Claude JSONL parser 曾经用局部 <code>activeTurnId</code> 推断当前 turn。整文件读取时， 这通常能靠顺序凑对；增量读取时，parser 每次只拿到新增片段，局部状态会从空开始。 如果新增片段刚好从 attachment、assistant 或 tool result 开始，parser 就可能把 <code>uuid</code> / <code>parentUuid</code> 当成新的 turn root，导致同一轮 Claude 输出被拆成多个 <code>mirror:&lt;bridge-session-id&gt;:&lt;turn-id&gt;</code> streamKey，用户会看到重复或碎片化 mirror 卡片。</p><p>Claude source 应维护 provider-specific parser state，并把所有相关记录映射到一个 稳定的 <code>rootTurnId</code>：</p><ul><li>真实 user prompt：创建 root，优先使用 <code>promptId</code>，否则使用 user <code>uuid</code>。</li><li>attachment：通过 <code>parentUuid</code> 继承 root，并登记自身 <code>uuid -&gt; root</code>。</li><li>assistant text / assistant tool_use：通过 <code>parentUuid</code> 继承 root，并登记自身 <code>uuid -&gt; root</code>。</li><li>tool_use：同时登记 <code>tool_use.id -&gt; root</code>。</li><li>tool_result：优先通过 <code>tool_use_id</code> 找 root；否则通过 <code>parentUuid</code> 继承 root。</li><li>interrupt、permission、synthetic user message：如果 <code>promptId</code> 或 parent chain 命中 已有 root，继续归入同一个 root，不创建新的业务 turn。</li></ul><p>parser state 至少需要保存：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>activeTurnId</span></span>
<span class="line"><span>uuidToRootTurnId</span></span>
<span class="line"><span>promptIdToRootTurnId</span></span>
<span class="line"><span>toolUseIdToRootTurnId</span></span></code></pre></div><p>增量读取必须返回下一次读取所需的 state。整文件读取和任意分段增量读取应生成相同的 record turnId 序列。</p><p>Mirror suppression 不应承担 turn identity 推断。它只处理 bridge 发起 turn 的回声：</p><ol><li>IM 发起 prompt 时，登记 <code>BridgeSession + normalized prompt</code>。</li><li>Claude JSONL source 首次识别到对应 root turn 后，所有该 root 的 records 都带同一个 turnId。</li><li><code>routeRuntimeRecords</code> 或 suppression 决定这些 records 是 active turn 的终态，还是 应丢弃的回声。</li></ol><p>这样同一 Claude turn 不会在主 <code>im:</code> 卡片完成后，又以多个 <code>mirror:</code> streamKey 再发一次。</p><p>相关源码：</p><ul><li>Claude JSONL source：<code>src/runtime/claude/session-jsonl.ts</code></li><li>Mirror reconcile：<code>src/bridge/mirror/reconcile-core.ts</code></li><li>Mirror delivery reducer：<code>src/bridge/mirror/turns.ts</code></li><li>Mirror suppression：<code>src/bridge/mirror/suppression.ts</code></li></ul><h2 id="命令应用层" tabindex="-1">命令应用层 <a class="header-anchor" href="#命令应用层" aria-label="Permalink to &quot;命令应用层&quot;">​</a></h2><p>命令层负责把用户输入的 slash command 解释成明确的业务动作。它不拥有会话生命周期，也不直接拥有通道连接；它读取当前聊天和会话状态，决定要执行哪个 use-case，再把展示结果交给 delivery。</p>`,37)),r(d,{code64:""}),e[7]||(e[7]=t('<h3 id="设计理念-2" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念-2" aria-label="Permalink to &quot;设计理念&quot;">​</a></h3><p>命令层的边界是“解释用户意图和组织展示”，不是“承载所有业务状态”。会话、绑定、线程接管、归档和工作目录等规则归会话模块负责；命令层只做 slash 解析、参数校验、调用 use-case 和生成用户可读结果。</p><p>命令也要服从 lane。只读状态查询可以走 chat lane；会改变会话绑定或运行配置的命令必须进入 session lane 并声明 barrier；停止和权限快捷回复这类控制动作走 control lane。</p><h3 id="命令类型" tabindex="-1">命令类型 <a class="header-anchor" href="#命令类型" aria-label="Permalink to &quot;命令类型&quot;">​</a></h3><p>命令分为三类：</p><ul><li>通道级命令：不要求当前 chat 已经有 session，例如 <code>/status</code>、<code>/t</code>。</li><li>会话级命令：读取或修改当前 chat 的 ChannelChat/session，例如 <code>/new</code>、<code>/t 1</code>、<code>/provider</code>、<code>/his</code>、<code>/stop</code>。</li><li>全局配置命令：通过某个 chat 触发，但实际修改全局设置，例如 <code>/ui</code>、<code>/his limit</code>。</li></ul><p>当前命令重构的完成标准是模块边界优先，而不是继续把每条命令拆得很细：</p><ul><li><code>bridge/host</code> 是生产代码里唯一直接调用 <code>bridge/command</code> 的上层 owner。</li><li><code>channels</code>、<code>bridge/turn</code>、<code>runtime</code>、<code>storage</code>、<code>operator-ui</code> 不直接依赖 <code>bridge/command</code>。</li><li>跨命令和 turn 共用的回调协议放在共享 callback 边界里，避免 turn 反向依赖 command。</li><li>command 不直接 import host 实现；全局 context、会话绑定 router 和 startup target 都有 host 外的共享入口，host 下同名文件只保留兼容 facade。</li></ul><h3 id="模块入口-1" tabindex="-1">模块入口 <a class="header-anchor" href="#模块入口-1" aria-label="Permalink to &quot;模块入口&quot;">​</a></h3><ul><li>命令分发入口：<code>src/bridge/command/dispatch.ts</code></li><li>会话命令聚合：<code>src/bridge/command/session-thread.ts</code></li><li>会话 use-case：<code>src/bridge/session/command-use-cases/</code></li><li>runtime 设置命令：<code>src/bridge/command/runtime-settings.ts</code></li><li>provider 切换命令：<code>src/bridge/command/provider-settings.ts</code></li><li>终端与本地工具命令：<code>src/bridge/command/tmux.ts</code>、<code>src/bridge/command/pty.ts</code>、<code>src/bridge/command/shell.ts</code></li><li>自动任务命令：<code>src/bridge/command/auto.ts</code></li><li>命令展示：<code>src/bridge/command/presentation/</code></li><li>共享 callback 协议：<code>src/bridge/callbacks/</code></li><li>全局 context 与会话绑定：<code>src/bridge/context.ts</code>、<code>src/bridge/session/channel-router.ts</code>、<code>src/bridge/startup-notice-target.ts</code></li></ul><h2 id="本地工作台" tabindex="-1">本地工作台 <a class="header-anchor" href="#本地工作台" aria-label="Permalink to &quot;本地工作台&quot;">​</a></h2><p>本地 Web 工作台是 bridge 的管理面。它不替代 IM 工作流，而是提供更适合浏览、配置和诊断的本地页面：看所有 session、检查通道实例、编辑配置、查看历史和确认服务状态。</p><h3 id="设计理念-3" tabindex="-1">设计理念 <a class="header-anchor" href="#设计理念-3" aria-label="Permalink to &quot;设计理念&quot;">​</a></h3><p>工作台里的可变操作仍然围绕 <code>BridgeSession.id</code>。本机 Codex thread 在未接管前只是只读候选项；一旦用户要重命名、绑定、配置、删除或设置默认目标，就先 materialize 成 <code>BridgeSession</code>，再进入同一套会话生命周期。</p><h3 id="主要页面" tabindex="-1">主要页面 <a class="header-anchor" href="#主要页面" aria-label="Permalink to &quot;主要页面&quot;">​</a></h3><ul><li>概览：显示 UI、bridge、通道数量和进程状态。</li><li>Sessions：列出 Bridge 会话和本机可发现的 Codex 线程。</li><li>Session History：查看某个 session 的历史。</li><li>Channels：管理飞书通道实例、ChannelChat、默认目标和测试。</li><li>Config：编辑全局默认设置。</li><li>命令：展示 IM 命令帮助。</li></ul><h3 id="模块入口-2" tabindex="-1">模块入口 <a class="header-anchor" href="#模块入口-2" aria-label="Permalink to &quot;模块入口&quot;">​</a></h3><ul><li>UI server：<code>src/operator-ui/server.ts</code></li><li>页面 shell：<code>src/operator-ui/shell.ts</code></li><li>session 应用层：<code>src/operator-ui/application/session.ts</code></li><li>channel 应用层：<code>src/operator-ui/application/channel.ts</code></li><li>config 应用层：<code>src/operator-ui/application/config.ts</code></li></ul><h2 id="数据归属" tabindex="-1">数据归属 <a class="header-anchor" href="#数据归属" aria-label="Permalink to &quot;数据归属&quot;">​</a></h2><p>CodeLark 自有数据位于 <code>~/.codelark</code>：</p><ul><li><code>config.toml</code>：全局主配置，使用 v2 TOML shape。</li><li><code>config/sessions/</code>、<code>config/channels/</code>：Session / Channel 级 TOML 覆盖，复用同一套 shape。</li><li><code>config.json</code> / <code>config.env</code>：旧版 v1 迁移输入，迁移成功后归档，不再作为运行时配置来源。</li><li><code>data/sessions.json</code>：BridgeSession，只保存本地工作会话身份、运行状态和 provider runtime identity；用户配置覆盖保存在 scoped TOML。</li><li><code>data/channel-chats.json</code>：ChannelChat，只保存 IM chat 身份和 <code>bridgeSessionId</code>。</li><li><code>data/channel-default-targets.json</code>：通道实例的默认目标。</li><li><code>data/messages/&lt;sessionId&gt;.json</code>：Bridge 消息缓存。</li><li><code>data/permissions.json</code>：权限回调链接。</li><li><code>data/offsets.json</code>：adapter 消费偏移。</li><li><code>data/dedup.json</code>：去重时间戳。</li><li><code>data/audit.jsonl</code>：审计记录，按行追加；旧 <code>data/audit.json</code> 仍作为 legacy 数组读取。</li><li><code>thread-table-messages.json</code>：线程卡片消息记录。</li><li>bridge 和 UI 的 runtime 状态文件。</li></ul><p>Codex 自有数据仍位于 <code>~/.codex</code>。CodeLark 只读使用它们。</p><h2 id="迁移边界" tabindex="-1">迁移边界 <a class="header-anchor" href="#迁移边界" aria-label="Permalink to &quot;迁移边界&quot;">​</a></h2><p>启动迁移负责把旧 session thread 身份字段收敛到 <code>BridgeSession.codex_thread_id</code>。旧 <code>data/bindings.json</code> 到 <code>data/channel-chats.json</code> 的迁移使用显式脚本执行，不在运行时代码中保留兼容读取：</p><ul><li>session 上旧的 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_id</code> 会迁移成 <code>codex_thread_id</code>。</li><li><code>scripts/migrate-bindings-to-channel-chats.js</code> 只保留旧 binding 中 <code>active: true</code> 的记录，并把旧 binding 上的运行时字段迁到它指向的 session 空字段；成功写入 <code>channel-chats.json</code> 后会删除旧 <code>data/bindings.json</code>。</li><li>旧 selector 字符串只允许作为迁移输入；运行时代码应使用 <code>BridgeSession.id</code> 和显式的 Codex thread import。</li></ul><p>迁移后的不变量：</p><ul><li>Codex thread 身份只在 session。</li><li>ChannelChat 只指向 session。</li><li>channel 只负责平台入口和消息投递。</li></ul><h2 id="术语规则" tabindex="-1">术语规则 <a class="header-anchor" href="#术语规则" aria-label="Permalink to &quot;术语规则&quot;">​</a></h2><ul><li>使用 <code>codex_thread_id</code> 表示唯一持久化的 Codex thread 身份。</li><li>不新增 <code>thread_id</code> 作为替代字段。</li><li>不把 <code>sdk_session_id</code>、<code>desktop_thread_id</code>、<code>thread_origin</code> 当运行时 fallback。</li><li>用户文案可以使用“本地 Codex 会话”或“Codex 线程”。</li><li>内部业务模型围绕 <code>BridgeSession</code>、<code>ChannelChat</code>、<code>IMChannel</code> 和 <code>codex_thread_id</code> 表达。</li><li><code>ChannelChat</code> 是 chat 到 BridgeSession 的关系，不是 chat 到 Codex thread 的关系。</li></ul>',29))])}const v=a(n,[["render",p]]);export{I as __pageData,v as default};
